import { writeFileSync, appendFileSync, mkdirSync, readFileSync } from "node:fs";
import { dirname } from "node:path";
import { probeWellKnown, SUITE_PATHS } from "./probe/probe.js";
const TIER_ORDER = {
    none: 0,
    minimal: 1,
    partial: 2,
    strong: 3,
    comprehensive: 4
};
const TIER_COLOR = {
    comprehensive: "brightgreen",
    strong: "green",
    partial: "yellow",
    minimal: "orange",
    none: "lightgrey"
};
export async function run(env) {
    const rawDomain = required(env.inputs, "domain");
    const domain = resolveDomain(rawDomain, env);
    const minScore = clampInt(env.inputs.min_score, 0, 0, 100);
    const minTierInput = (env.inputs.min_tier ?? "none").toLowerCase();
    if (!(minTierInput in TIER_ORDER)) {
        throw new Error(`input "min-tier" must be one of: none, minimal, partial, strong, comprehensive — got "${minTierInput}"`);
    }
    const timeoutMs = clampInt(env.inputs.timeout_ms, 5000, 100, 60000);
    const commentOnPr = env.inputs.comment_on_pr ?? "auto";
    const outputPath = env.inputs.output_path?.trim() || "";
    const badgeOutput = env.inputs.badge_output?.trim() || "";
    const token = env.inputs.github_token ?? "";
    const doProbe = env.probe ?? ((d, o) => probeWellKnown(d, o));
    const writeOutFile = env.writeFile ?? ((p, c) => {
        mkdirSync(dirname(p), { recursive: true });
        writeFileSync(p, c, "utf8");
    });
    const read = env.readFile ?? ((p) => readFileSync(p, "utf8"));
    const write = env.write ?? ((line) => process.stdout.write(`${line}\n`));
    write(`::notice::Probing ${domain} for 11 Suite documents (timeout ${timeoutMs}ms)`);
    const probe = await doProbe(domain, { timeout: timeoutMs });
    setOutput(env, "score", String(probe.score));
    setOutput(env, "tier", probe.tier);
    setOutput(env, "published-count", String(probe.published.length));
    setOutput(env, "missing-count", String(probe.missing.length));
    setOutput(env, "published", probe.published.join(","));
    setOutput(env, "missing", probe.missing.join(","));
    let outputWritten = false;
    if (outputPath) {
        try {
            writeOutFile(outputPath, JSON.stringify(probe, null, 2) + "\n");
            outputWritten = true;
            write(`::notice::Wrote probe receipt to "${outputPath}".`);
        }
        catch (e) {
            write(`::error::could not write output-path "${outputPath}" — ${e.message}`);
            return baseFail(domain, probe, "write failed");
        }
    }
    let badgeWritten = false;
    if (badgeOutput) {
        try {
            writeOutFile(badgeOutput, renderBadgeSvg(probe.score, probe.tier));
            badgeWritten = true;
            write(`::notice::Wrote self-score SVG badge to "${badgeOutput}".`);
        }
        catch (e) {
            write(`::error::could not write badge-output "${badgeOutput}" — ${e.message}`);
            return baseFail(domain, probe, "badge write failed");
        }
    }
    const markdown = renderMarkdown(probe);
    write(`\n${markdown}\n`);
    // PR comment.
    const isPullRequest = env.GITHUB_EVENT_NAME === "pull_request";
    const wantsComment = commentOnPr === "true" || (commentOnPr === "auto" && isPullRequest);
    let commentPosted = false;
    let reason;
    if (wantsComment) {
        if (!token) {
            reason = "no github-token provided";
        }
        else if (!env.GITHUB_EVENT_PATH) {
            reason = "no GITHUB_EVENT_PATH";
        }
        else if (!env.GITHUB_REPOSITORY) {
            reason = "no GITHUB_REPOSITORY";
        }
        else {
            const event = JSON.parse(read(env.GITHUB_EVENT_PATH));
            const issueNumber = event.number ?? event.pull_request?.number;
            if (!issueNumber) {
                reason = "no PR number in event payload";
            }
            else {
                const body = `### Procurement Pulse — self-score for \`${domain}\`\n\n${markdown}\n\n_Generated by [procurement-pulse-action](https://github.com/mizcausevic-dev/procurement-pulse-action)._`;
                const poster = env.postComment ?? defaultPostComment;
                await poster({ token, repo: env.GITHUB_REPOSITORY, issueNumber, body });
                commentPosted = true;
            }
        }
    }
    // Threshold gates.
    if (probe.score < minScore) {
        write(`::error::Pulse self-score ${probe.score}/100 is below the min-score gate (${minScore}).`);
        return { exitCode: 1, domain, probe, commentPosted, outputWritten, badgeWritten, reason };
    }
    if (TIER_ORDER[probe.tier] < TIER_ORDER[minTierInput]) {
        write(`::error::Pulse tier "${probe.tier}" is below the min-tier gate ("${minTierInput}").`);
        return { exitCode: 1, domain, probe, commentPosted, outputWritten, badgeWritten, reason };
    }
    return { exitCode: 0, domain, probe, commentPosted, outputWritten, badgeWritten, reason };
}
function resolveDomain(rawDomain, env) {
    if (rawDomain.toLowerCase() !== "auto")
        return rawDomain;
    // Best-effort: derive a probe target from the GH context.
    const owner = env.GITHUB_REPOSITORY_OWNER;
    if (!owner) {
        throw new Error(`input "domain" was "auto" but GITHUB_REPOSITORY_OWNER is not set; please pass an explicit domain.`);
    }
    return `${owner}.github.io`;
}
function required(inputs, name) {
    const v = inputs[name];
    if (!v || v.length === 0)
        throw new Error(`input "${name}" is required`);
    return v;
}
function clampInt(raw, fallback, min, max) {
    const n = raw === undefined ? fallback : Number.parseInt(raw, 10);
    if (!Number.isFinite(n) || n < min || n > max) {
        throw new Error(`input out of range: expected ${min}..${max}, got "${raw}"`);
    }
    return n;
}
function setOutput(env, key, value) {
    if (env.GITHUB_OUTPUT)
        appendFileSync(env.GITHUB_OUTPUT, `${key}=${value}\n`);
}
function baseFail(domain, probe, reason) {
    return { exitCode: 1, domain, probe, commentPosted: false, outputWritten: false, badgeWritten: false, reason };
}
function renderMarkdown(probe) {
    const lines = [];
    lines.push(`**Score:** ${probe.score} / 100 · **Tier:** \`${probe.tier}\` · ${probe.published.length} / 11 documents published`);
    lines.push("");
    lines.push("| Spec | Status |");
    lines.push("|---|---|");
    const slugs = Object.keys(SUITE_PATHS);
    for (const slug of slugs) {
        const r = probe.documents[slug];
        const icon = r.found ? "✅" : "❌";
        const detail = r.found
            ? r.version
                ? `\`${r.version}\``
                : `HTTP ${r.status}`
            : r.error ?? `HTTP ${r.status}`;
        lines.push(`| \`${slug}\` | ${icon} ${detail} |`);
    }
    lines.push("");
    if (probe.missing.length > 0) {
        lines.push(`_Missing: ${probe.missing.map((s) => `\`${s}\``).join(", ")}_`);
    }
    else {
        lines.push(`_All 11 Suite documents published. Comprehensive disclosure._`);
    }
    return lines.join("\n");
}
/**
 * Render a Shields.io-style SVG badge. The mark renders as "kg pulse | NN/100"
 * with a tier-coloured right half. Self-contained (no external CSS / fonts),
 * suitable for embedding directly in a README.
 */
function renderBadgeSvg(score, tier) {
    const color = TIER_COLOR[tier] ?? "lightgrey";
    const colorHex = {
        brightgreen: "#4c1",
        green: "#97CA00",
        yellow: "#dfb317",
        orange: "#fe7d37",
        lightgrey: "#9f9f9f"
    };
    const right = colorHex[color] ?? "#9f9f9f";
    const label = "kg pulse";
    const value = `${score}/100`;
    // Approximate text-width calculation — Shields ~7px/char + 10px padding per side.
    const labelWidth = label.length * 7 + 14;
    const valueWidth = value.length * 7 + 14;
    const totalWidth = labelWidth + valueWidth;
    return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="${totalWidth}" height="20" role="img" aria-label="${label}: ${value}">
  <title>${label}: ${value} (tier: ${tier})</title>
  <linearGradient id="s" x2="0" y2="100%">
    <stop offset="0" stop-color="#fff" stop-opacity=".7"/>
    <stop offset=".1" stop-color="#aaa" stop-opacity=".1"/>
    <stop offset=".9" stop-color="#000" stop-opacity=".3"/>
    <stop offset="1" stop-color="#000" stop-opacity=".5"/>
  </linearGradient>
  <clipPath id="r"><rect width="${totalWidth}" height="20" rx="3"/></clipPath>
  <g clip-path="url(#r)">
    <rect width="${labelWidth}" height="20" fill="#555"/>
    <rect x="${labelWidth}" width="${valueWidth}" height="20" fill="${right}"/>
    <rect width="${totalWidth}" height="20" fill="url(#s)"/>
  </g>
  <g fill="#fff" text-anchor="middle" font-family="Verdana,Geneva,DejaVu Sans,sans-serif" font-size="11">
    <text x="${labelWidth / 2}" y="14">${label}</text>
    <text x="${labelWidth + valueWidth / 2}" y="14">${value}</text>
  </g>
</svg>
`;
}
async function defaultPostComment(args) {
    const r = await fetch(`https://api.github.com/repos/${args.repo}/issues/${args.issueNumber}/comments`, {
        method: "POST",
        headers: {
            Accept: "application/vnd.github+json",
            Authorization: `Bearer ${args.token}`,
            "X-GitHub-Api-Version": "2022-11-28"
        },
        body: JSON.stringify({ body: args.body })
    });
    if (!r.ok)
        throw new Error(`GitHub API comment failed: ${r.status} ${await r.text()}`);
}
